  blue:    ["#0ea5e9","#38bdf8","#7dd3fc","#0284c7","#bae6fd","#0369a1"],
  warm:    ["#f97316","#fb923c","#fbbf24","#f43f5e","#e11d48","#c2410c"],
  dark:    ["#a78bfa","#34d399","#fb7185","#fbbf24","#60a5fa","#f472b6"],
};

const fmtAxis = (v) => {
  if (typeof v !== "number") return v;
  if (v >= 1_000_000) return `${(v/1_000_000).toFixed(1)}M`;
  if (v >= 1_000)     return `${(v/1_000).toFixed(1)}K`;
  return Number.isInteger(v) ? v : v.toFixed(1);
};
const fmtSpeak = (v) => {
  if (typeof v !== "number") return v;
  if (v >= 1_000_000) return `${(v/1_000_000).toFixed(1)} million`;
  if (v >= 1_000)     return `${(v/1_000).toFixed(1)} thousand`;
  return Number.isInteger(v) ? v : parseFloat(v.toFixed(2));
};

function buildExplanation(chart) {
  const data = chart.data || [];
  const xKey = chart.x_axis;
  if (!data.length) return `This chart titled "${chart.title}" has no data.`;
  const valKeys = Object.keys(data[0]).filter(k => k !== xKey && typeof data[0][k]==="number");
  if (!valKeys.length) return `This chart shows ${chart.title}.`;
  const key = valKeys[0];
  const sorted = [...data].sort((a,b)=>(b[key]||0)-(a[key]||0));
  const top = sorted[0]; const bot = sorted[sorted.length-1];
  const total = data.reduce((s,r)=>s+(r[key]||0),0);
  const avg = total/data.length;
  let txt = `This chart is about ${chart.title}. `;
  if (chart.chart_type==="pie") txt += `It shows how ${key} is distributed. `;
  else if (chart.chart_type==="line"||chart.chart_type==="area") txt += `It shows the trend of ${key} over time. `;
  else txt += `It compares ${key} across different ${xKey}s. `;
  if (top?.[xKey]!=null) txt += `The highest value is ${fmtSpeak(top[key])}, belonging to ${top[xKey]}. `;
  if (bot?.[xKey]!=null&&bot[xKey]!==top[xKey]) txt += `The lowest is ${fmtSpeak(bot[key])}, belonging to ${bot[xKey]}. `;
  if (data.length>2) txt += `Total is ${fmtSpeak(total)}, average ${fmtSpeak(avg)}. `;
  if ((chart.chart_type==="line"||chart.chart_type==="area")&&data.length>=2) {
    const diff = data[data.length-1][key]-data[0][key];
    const pct  = data[0][key]!==0?Math.abs(diff/data[0][key]*100).toFixed(1):0;
    txt += diff>0?`Upward trend, up ${pct}%. `:`Downward trend, down ${pct}%. `;
  }
  txt += `${data.length} data points total.`;
  return txt;
}

function speak(text, onStart, onEnd) {
  if (!window.speechSynthesis) { alert("Voice not supported. Use Chrome or Edge."); return; }
  window.speechSynthesis.cancel();
  const u = new SpeechSynthesisUtterance(text);
  u.rate=0.88; u.pitch=1; u.volume=1;
  const vs = window.speechSynthesis.getVoices();
  const best = vs.find(v=>v.lang.startsWith("en")&&(v.name.includes("Google")||v.name.includes("Natural"))) || vs.find(v=>v.lang.startsWith("en"));
  if (best) u.voice = best;
  u.onstart=onStart; u.onend=onEnd; u.onerror=onEnd;
  window.speechSynthesis.speak(u);
}

const Tooltip_ = ({ active, payload, label }) => {
  if (!active||!payload?.length) return null;
  return (
    <div style={{ background:"#1a2236", border:"1px solid #243048", borderRadius:10, padding:"10px 14px", boxShadow:"0 8px 24px rgba(0,0,0,0.5)" }}>
      <p style={{ fontSize:11, color:"#8896b3", marginBottom:6 }}>{label}</p>
      {payload.map((p,i)=>(<p key={i} style={{ fontSize:12, fontWeight:500, color:p.color }}>{p.name}: <b>{fmtAxis(p.value)}</b></p>))}
    </div>
  );
};

export default function ChartCard({ chart, colorSchema="default", index=0 }) {
  const [speaking, setSpeaking]     = useState(false);
  const [showExp, setShowExp]       = useState(false);
  const [explanation, setExp]       = useState("");
  const colors = PALETTES[colorSchema]||PALETTES.default;
  const data   = chart.data||[];
  const xKey   = chart.x_axis;
  const dataKeys = data.length>0 ? Object.keys(data[0]).filter(k=>k!==xKey) : [chart.y_axis];

  const handleSpeak = () => {
    if (speaking) { window.speechSynthesis.cancel(); setSpeaking(false); return; }
    const txt = buildExplanation(chart);
    setExp(txt); setShowExp(true);
    speak(txt, ()=>setSpeaking(true), ()=>setSpeaking(false));
  };

  const renderChart = () => {
    const axis = { tick:{ fill:"#8896b3", fontSize:10 }, axisLine:false, tickLine:false };
    const grid = <CartesianGrid strokeDasharray="3 3" stroke="#1e2a42" vertical={false}/>;
    switch (chart.chart_type) {
      case "line": return (
        <LineChart data={data}>
          {grid}<XAxis dataKey={xKey} {...axis}/><YAxis tickFormatter={fmtAxis} {...axis}/><Tooltip content={<Tooltip_/>}/><Legend wrapperStyle={{ fontSize:11 }}/>
          {dataKeys.map((k,i)=>(<Line key={k} type="monotone" dataKey={k} stroke={colors[i%colors.length]} strokeWidth={2.5} dot={{ r:3 }} activeDot={{ r:5 }}/>))}
        </LineChart>
      );
      case "area": return (
        <AreaChart data={data}>
          <defs>{dataKeys.map((k,i)=>(<linearGradient key={k} id={`ag-${index}-${i}`} x1="0" y1="0" x2="0" y2="1"><stop offset="5%" stopColor={colors[i%colors.length]} stopOpacity={0.25}/><stop offset="95%" stopColor={colors[i%colors.length]} stopOpacity={0}/></linearGradient>))}</defs>
          {grid}<XAxis dataKey={xKey} {...axis}/><YAxis tickFormatter={fmtAxis} {...axis}/><Tooltip content={<Tooltip_/>}/>
          {dataKeys.map((k,i)=>(<Area key={k} type="monotone" dataKey={k} stroke={colors[i%colors.length]} strokeWidth={2} fill={`url(#ag-${index}-${i})`}/>))}
        </AreaChart>
      );
      case "pie": return (
        <PieChart><Pie data={data} dataKey={dataKeys[0]} nameKey={xKey} cx="50%" cy="50%" outerRadius={90} innerRadius={42} paddingAngle={3} strokeWidth={0}>
          {data.map((_,i)=>(<Cell key={i} fill={colors[i%colors.length]}/>))}
        </Pie><Tooltip content={<Tooltip_/>}/><Legend wrapperStyle={{ fontSize:11 }}/></PieChart>
      );
      default: return (
        <BarChart data={data} barCategoryGap="28%">
          {grid}<XAxis dataKey={xKey} {...axis}/><YAxis tickFormatter={fmtAxis} {...axis}/><Tooltip content={<Tooltip_/>}/><Legend wrapperStyle={{ fontSize:11 }}/>
          {dataKeys.map((k,i)=>(<Bar key={k} dataKey={k} fill={colors[i%colors.length]} radius={[4,4,0,0]} maxBarSize={52}/>))}
        </BarChart>
      );
    }
  };

  return (
    <div style={{ ...S.card, animationDelay:`${index*0.08}s` }} className="fade-up">
      <div style={S.hdr}>
        <div style={S.hdrLeft}>
          <div style={{ ...S.typeBadge, background:`${colors[0]}18`, color:colors[0], border:`1px solid ${colors[0]}30` }}>{chart.chart_type}</div>
          <h3 style={S.cardTitle}>{chart.title}</h3>
        </div>
        <button style={{ ...S.speakBtn, ...(speaking?S.speakOn:{}) }} onClick={handleSpeak} title={speaking?"Stop":"Explain this chart"}>
          {speaking ? (
            <><div style={S.waves}><span style={{ ...S.wave, animationDelay:"0s" }}/><span style={{ ...S.wave, animationDelay:"0.12s" }}/><span style={{ ...S.wave, animationDelay:"0.24s" }}/></div>Stop</>
          ) : (
            <><svg width="13" height="13" viewBox="0 0 16 16" fill="none"><path d="M3 6H1v4h2l4 3V3L3 6z" fill="currentColor"/><path d="M11.5 8a3.5 3.5 0 00-2-3.15v6.3A3.5 3.5 0 0011.5 8z" fill="currentColor"/><path d="M14 8a6 6 0 00-3-5.2v1.56A4.5 4.5 0 0113 8a4.5 4.5 0 01-2 3.64v1.56A6 6 0 0014 8z" fill="currentColor"/></svg>Explain</>
          )}
        </button>
      </div>

      <div style={{ padding:"14px 8px 8px" }}>
        <ResponsiveContainer width="100%" height={230}>{renderChart()}</ResponsiveContainer>
      </div>

      {showExp && (
        <div style={S.expBox} className="fade-in">
          <div style={S.expHdr}>
            <div style={{ ...S.expDot, animation: speaking?"pulse 1.2s infinite":"none" }}/>
            <span style={S.expLabel}>{speaking?"🔊 Speaking…":"📋 Explanation"}</span>
            <button style={S.expClose} onClick={()=>{setShowExp(false);window.speechSynthesis.cancel();setSpeaking(false);}}>✕</button>
          </div>
          <p style={S.expTxt}>{explanation}</p>
        </div>
      )}
    </div>
  );
}

